INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e6ba6e9-7942-50bb-aa6d-a02b7db41896', '3175611f-46ae-53ca-8b70-580d3231f54c', 'بتطبيق مبدأ الجداء المعدوم، ما حلول المعادلة (x − 4)(x + 2) = 0 ؟', '[{"id":"a","text":"x = 4 أو x = 2"},{"id":"b","text":"x = 4 أو x = −2"},{"id":"c","text":"x = −4 أو x = 2"},{"id":"d","text":"x = −4 أو x = −2"}]'::jsonb, 'b', 'a × b = 0 ⟺ a = 0 أو b = 0. إمّا x − 4 = 0 فـ x = 4، وإمّا x + 2 = 0 فـ x = −2.', 3)
