  ('b3698968-9bdd-5a04-87a8-d5f872fa3268', 'e9b1fb37-38ae-5b12-a38b-c6f536ff90a7', 'math', 'تمرين: حلّ جُمل معادلتَين بطريقتَي التعويض والتأليف', 2, 65, 13, 'practice', 'admin', 1)
