INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0115bb4-ea6e-5564-8c32-74edcd629b45', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة الخطية f تُعرَّف بـ f(x) = 3x. ما قيمة f(4) ؟', '[{"id":"a","text":"12"},{"id":"b","text":"7"},{"id":"c","text":"16"},{"id":"d","text":"34"}]'::jsonb, 'a', 'f(4) = 3 × 4 = 12. الدالة الخطية f(x) = ax تعمل بضرب x في معامل التناسب a = 3.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a3da51fe-f3f0-58c9-89a8-d6bbeebf688f', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة التآلفية f تُعرَّف بـ f(x) = 2x + 1. ما قيمة f(3) ؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"9"},{"id":"d","text":"4"}]'::jsonb, 'b', 'f(3) = 2 × 3 + 1 = 6 + 1 = 7. نعوّض x = 3 في الصيغة f(x) = 2x + 1.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('57f85ba0-c2d2-571b-b686-73e29445f52a', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة الخطية f تُعرَّف بـ f(x) = ax وتمرّ بياناتها بالنقطة (2 ; 8). ما قيمة a ؟', '[{"id":"a","text":"2"},{"id":"b","text":"6"},{"id":"c","text":"4"},{"id":"d","text":"16"}]'::jsonb, 'c', 'بما أنّ النقطة (2 ; 8) تنتمي للبيان، فإنّ f(2) = 8، أي a × 2 = 8، إذن a = 8 ÷ 2 = 4.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f830ff4c-84fe-5bc7-aa13-3c7505a5978b', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة التآلفية f تُعرَّف بـ f(x) = −2x + 5. ما قيمة x حين f(x) = 0 (أي سابقة الصفر) ؟', '[{"id":"a","text":"5"},{"id":"b","text":"−5"},{"id":"c","text":"2.5"},{"id":"d","text":"10"}]'::jsonb, 'c', 'نحلّ −2x + 5 = 0، إذن −2x = −5، x = 5/2 = 2.5. هذه هي سابقة الصفر، أي نقطة تقاطع المستقيم مع محور الفواصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d1f9b78-da86-566d-9b23-ea9bd72d2d40', '19994972-418b-5eeb-90e0-8db612ea6855', 'بيان دالة تآلفية يمرّ بالنقطتَين (0 ; 3) و (1 ; 5). ما هي الدالة؟', '[{"id":"a","text":"f(x) = 3x + 5"},{"id":"b","text":"f(x) = 2x + 3"},{"id":"c","text":"f(x) = 5x"},{"id":"d","text":"f(x) = 3x − 2"}]'::jsonb, 'b', 'من النقطة (0 ; 3) نستنتج b = f(0) = 3. معامل التوجيه: a = (5 − 3) ÷ (1 − 0) = 2. إذن f(x) = 2x + 3.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69267cbe-128b-5be3-b5da-b818fbeb0ed7', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة التآلفية f تُعرَّف بـ f(x) = 3x + 2. ما قيمة x إذا كانت f(x) = 14 ؟', '[{"id":"a","text":"5"},{"id":"b","text":"6"},{"id":"c","text":"4"},{"id":"d","text":"3"}]'::jsonb, 'c', 'نحلّ 3x + 2 = 14، إذن 3x = 12، x = 4. التحقّق: f(4) = 3(4) + 2 = 14 ✓.', 6)
