  ('6344760c-5d13-5ace-be92-9275a52c654a', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', '⚔️ زعيم الفصل: الدوال والمستقيمات — التحدّي الأعلى', 3, 120, 30, 'boss', 'admin', 2)
