INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f583e61-7fad-526b-a7dc-62f7ad6a37af', '6344760c-5d13-5ace-be92-9275a52c654a', 'بيان دالة تآلفية يمرّ بالنقطتَين A(1 ; 5) و B(3 ; 11). ما قيمة معامل التوجيه a ؟', '[{"id":"a","text":"2"},{"id":"b","text":"5"},{"id":"c","text":"3"},{"id":"d","text":"6"}]'::jsonb, 'c', 'a = (y_B − y_A) ÷ (x_B − x_A) = (11 − 5) ÷ (3 − 1) = 6 ÷ 2 = 3.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
