  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70c72520-1938-5ed8-9f18-589953b27100', 'b6fdc318-4fb8-5cdf-a865-2ffd1468c8b7', 'في تمثيل بيانيّ على شكل قطاع دائري، فئة تمثّل 40 % من المجتمع. ما هي زاوية القطاع المقابل لها؟', '[{"id":"a","text":"40°"},{"id":"b","text":"144°"},{"id":"c","text":"120°"},{"id":"d","text":"80°"}]'::jsonb, 'b', 'زاوية القطاع = f_i × 360° = 0.40 × 360° = 144°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4184f2c6-ccca-5eb3-bae9-701caea1e475', 'b6fdc318-4fb8-5cdf-a865-2ffd1468c8b7', 'جدول تكرارات لعلامات: 10 (تكرار 3)، 12 (تكرار 5)، 14 (تكرار 2). ما هو التكرار المجمّع عند علامة 12؟', '[{"id":"a","text":"5"},{"id":"b","text":"8"},{"id":"c","text":"10"},{"id":"d","text":"3"}]'::jsonb, 'b', 'التكرار المجمّع عند 12 = تكرار 10 + تكرار 12 = 3 + 5 = 8.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
