INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da2cdf7b-de2a-5a15-af0f-ba0384fae853', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'في السلسلة المرتّبة ذاتها (n = 6): 5 ، 9 ، 9 ، 11 ، 13 ، 13. ما هو الوسيط؟', '[{"id":"a","text":"9"},{"id":"b","text":"10"},{"id":"c","text":"11"},{"id":"d","text":"9.5"}]'::jsonb, 'b', 'n = 6 (زوجي)، نأخذ متوسّط قيمتَي الرتبتين 3 و4. القيمة الثالثة = 9 والرابعة = 11. الوسيط = (9 + 11) ÷ 2 = 10.', 2)
