INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1f27784-df99-5e5e-99c5-db6baa9da9ed', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'حصل 5 تلاميذ على العلامة 12، و3 تلاميذ على العلامة 8، و2 تلاميذ على العلامة 16 (n = 10). ما هو المعدّل الحسابي؟', '[{"id":"a","text":"12"},{"id":"b","text":"11"},{"id":"c","text":"11.6"},{"id":"d","text":"10.8"}]'::jsonb, 'c', 'المجموع = (5 × 12) + (3 × 8) + (2 × 16) = 60 + 24 + 32 = 116. المعدّل = 116 ÷ 10 = 11.6.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac35bf2e-668e-5f5f-9d8f-b2c572a3747a', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'في فصل من 60 تلميذًا، حصل 15 تلميذًا على علامة 10. ما هي زاوية القطاع الدائري المقابل لهذه الفئة؟', '[{"id":"a","text":"60°"},{"id":"b","text":"54°"},{"id":"c","text":"90°"},{"id":"d","text":"36°"}]'::jsonb, 'c', 'التواتر = 15 ÷ 60 = 0.25. زاوية القطاع = 0.25 × 360° = 90°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
