  ('3b45c6b0-a990-57dc-9859-74a56930d2e2', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', 'تمرين: نظرية فيثاغورس والنسب المثلثية الأساسية', 1, 60, 12, 'practice', 'admin', 1)
