INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eca425d1-2139-5def-96d3-cc196a9f4ec3', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، AB = 5 cm وBC = 12 cm. ما طول الوتر AC؟', '[{"id":"a","text":"13 cm"},{"id":"b","text":"17 cm"},{"id":"c","text":"√17 cm"},{"id":"d","text":"169 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: AC² = AB² + BC² = 25 + 144 = 169، إذن AC = √169 = 13 cm. هذه هي الثلاثية المشهورة (5، 12، 13).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
