INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db4df78b-fd69-5434-bbb1-30a96a17ddd7', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة مركزها O، الزاوية المركزية AOB = 80°، وC نقطة على القوس الكبير. ما قيمة الزاوية المحيطية ACB؟', '[{"id":"a","text":"80°"},{"id":"b","text":"40°"},{"id":"c","text":"160°"},{"id":"d","text":"20°"}]'::jsonb, 'b', 'الزاوية المحيطية = نصف الزاوية المركزية المقابلة لنفس القوس. إذن الزاوية ACB = 80° ÷ 2 = 40°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d026040-efc2-5bee-ad33-605d9be079ed', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة مركزها O، الزاوية المحيطية PQR = 35°. ما قيمة الزاوية المركزية POR؟', '[{"id":"a","text":"17.5°"},{"id":"b","text":"35°"},{"id":"c","text":"70°"},{"id":"d","text":"105°"}]'::jsonb, 'c', 'الزاوية المركزية = ضعف الزاوية المحيطية. إذن الزاوية POR = 2 × 35° = 70°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('22d3cc36-de6f-5ee6-93b8-0045bcf36590', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة مركزها O، [AC] قطر، وB نقطة على الدائرة. إذا كانت الزاوية BAC = 40°، ما قيمة الزاوية BCA؟', '[{"id":"a","text":"40°"},{"id":"b","text":"50°"},{"id":"c","text":"90°"},{"id":"d","text":"140°"}]'::jsonb, 'b', 'بما أنّ [AC] قطر، فالزاوية ABC = 90° (زاوية محيطية في نصف دائرة). في المثلث ABC: الزاوية BCA = 180° − 90° − 40° = 50°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aef4d95c-4d0f-5861-80fb-c68afa8d3389', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة، الزاوية المحيطية ACB = 55°. وD نقطة أخرى على نفس القوس الكبير. ما قيمة الزاوية ADB؟', '[{"id":"a","text":"110°"},{"id":"b","text":"27.5°"},{"id":"c","text":"55°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'الزوايا المحيطية التي تحصر نفس القوس من الجهة نفسها متقايسة. إذن الزاوية ADB = الزاوية ACB = 55°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a48c2144-ae3e-556c-b104-d2a82f35721c', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة مركزها O، الزاوية المركزية AOB = 160°. ما قيمة الزاوية المحيطية ACB حيث C على القوس الصغير؟', '[{"id":"a","text":"80°"},{"id":"b","text":"100°"},{"id":"c","text":"160°"},{"id":"d","text":"320°"}]'::jsonb, 'b', 'عندما يكون C على القوس الصغير (من الجهة المعاكسة للزاوية المركزية)، فالزاوية المحيطية ACB تحصر القوس الكبير الذي قيسه 360° − 160° = 200°. إذن الزاوية ACB = 200° ÷ 2 = 100°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b483eb17-bcae-50fb-8596-e9366cd2b5db', '93dfdc12-2b72-5865-99a2-cbfa62c0ded0', 'في دائرة، الزاوية المحيطية ACB = 90°. ما الاستنتاج الصحيح؟', '[{"id":"a","text":"[AB] قطر للدائرة"},{"id":"b","text":"[AC] قطر للدائرة"},{"id":"c","text":"[BC] قطر للدائرة"},{"id":"d","text":"المثلث ACB متساوي الأضلاع"}]'::jsonb, 'a', 'إذا كانت الزاوية المحيطية ACB = 90°، فالزاوية المركزية المقابلة = 2 × 90° = 180°، وهذا يعني أنّ القوس المقابل هو نصف دائرة. إذن [AB] قطر، وهو عكس نظرية طالس في الدائرة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

