INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fb18edd-29f6-5550-9dee-b73269be157c', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة مركزها O، الزاوية المركزية AOB = 130°، وC نقطة على القوس الكبير. ما قيمة الزاوية ACB؟', '[{"id":"a","text":"65°"},{"id":"b","text":"130°"},{"id":"c","text":"260°"},{"id":"d","text":"115°"}]'::jsonb, 'a', 'الزاوية المحيطية = نصف الزاوية المركزية. الزاوية ACB = 130° ÷ 2 = 65°.', 1)
