INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cda659f-9474-5298-9483-cd9a342fab45', '8a45a71b-b2f9-5c7c-ad4d-674eab139c61', 'في المعلّم (O ; i ; j)، النقطتان A(1 ; 3) وB(5 ; −1). ما إحداثيّات الشعاع $\overrightarrow{AB}$؟', '[{"id":"a","text":"(4 ; −4)"},{"id":"b","text":"(−4 ; 4)"},{"id":"c","text":"(6 ; 2)"},{"id":"d","text":"(4 ; 4)"}]'::jsonb, 'a', 'إحداثيّات $\overrightarrow{AB}$: فاصلة B ناقص فاصلة A وترتيبة B ناقص ترتيبة A. أي (5−1 ; −1−3) = (4 ; −4).', 1)
