INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48cb8baf-edce-5753-8d55-cbb25021aa96', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(−2 ; 1) وB(4 ; 5). نقطة C(1 ; 3). هل C هي منتصف [AB]؟', '[{"id":"a","text":"لا، لأنّ المنتصف هو (1 ; 2)"},{"id":"b","text":"نعم، لأنّ $\\frac{-2+4}{2}=1$ و $\\frac{1+5}{2}=3$"},{"id":"c","text":"لا، لأنّ المنتصف هو (2 ; 3)"},{"id":"d","text":"لا، لأنّ المنتصف هو (1 ; 4)"}]'::jsonb, 'b', 'نحسب المنتصف: $\left(\frac{-2+4}{2} ; \frac{1+5}{2}\right) = \left(\frac{2}{2} ; \frac{6}{2}\right) = (1 ; 3)$. وبما أنّ C(1 ; 3) فإنّ C هي منتصف [AB].', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
