  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a0d2297-0ecc-5787-ac5a-94aa07e50e80', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'ABCD متوازي أضلاع بـ A(1 ; 2) وB(5 ; 2) وC(6 ; 5). ما إحداثيّات D؟', '[{"id":"a","text":"D(3 ; 5)"},{"id":"b","text":"D(2 ; 5)"},{"id":"c","text":"D(7 ; 5)"},{"id":"d","text":"D(0 ; 5)"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: $\overrightarrow{AB} = \overrightarrow{DC}$. $\overrightarrow{AB} = (4;0)$. $\overrightarrow{DC} = (4;0)$ أي $C - D = (4;0)$ فـD = C − (4;0) = (6−4 ; 5−0) = (2 ; 5). التحقّق: $\overrightarrow{AD}=(1;3)$ و $\overrightarrow{BC}=(1;3)$ متساويان ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7359118-a246-5e74-affa-d0f61216527d', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(2 ; −1) وB(6 ; −1) وC(6 ; 4). هل المثلّث ABC قائم الزاوية؟ وأين القائمة؟', '[{"id":"a","text":"نعم، القائمة في A لأنّ $AB^2 + AC^2 = BC^2$"},{"id":"b","text":"لا، ليس قائمًا"},{"id":"c","text":"نعم، القائمة في B لأنّ $AB^2 + BC^2 = AC^2$"},{"id":"d","text":"نعم، القائمة في C لأنّ $AC^2 + BC^2 = AB^2$"}]'::jsonb, 'c', '$AB = \sqrt{(6-2)^2+0^2} = 4$، $BC = \sqrt{0^2+(4+1)^2} = 5$، $AC = \sqrt{(6-2)^2+(4+1)^2} = \sqrt{16+25} = \sqrt{41}$. نتحقّق: $AB^2 + BC^2 = 16+25 = 41 = AC^2$ ✓. إذن القائمة في B.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c8e5bbe-7712-5a11-8da7-b237b1b6b03c', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(0 ; 0) وB(6 ; 0) وC(0 ; 8). I منتصف [BC]. ما المسافة AI؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"√45"},{"id":"d","text":"10"}]'::jsonb, 'a', 'المنتصف $I = \left(\frac{6+0}{2};\frac{0+8}{2}\right) = (3;4)$. ثمّ $AI = \sqrt{3^2+4^2} = \sqrt{9+16} = \sqrt{25} = 5$. ملاحظة: المثلّث ABC قائم في A وBC=10، والوسيط على وتر المثلّث القائم = نصف الوتر = 5 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd648144-7179-5365-9d15-3babfef30bf3', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(−3 ; 1) وB(1 ; 4). ما إحداثيّات النقطة C التي تجعل [AC] يحقّق $\overrightarrow{AC} = 2\overrightarrow{AB}$؟', '[{"id":"a","text":"C(5 ; 7)"},{"id":"b","text":"C(1 ; 4)"},{"id":"c","text":"C(−1 ; 2.5)"},{"id":"d","text":"C(8 ; 7)"}]'::jsonb, 'a', '$\overrightarrow{AB} = (1-(-3) ; 4-1) = (4;3)$. إذن $2\overrightarrow{AB} = (8;6)$. C = A + (8;6) = (−3+8 ; 1+6) = (5 ; 7).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

