INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('04e02825-43bc-5b75-a62d-875aa956e3da', '00789172-89dd-5cc2-8af9-730645c3c113', 'هرم قاعدته مثلّث قائم ساقاه 3 cm و4 cm، وارتفاع الهرم 10 cm. ما حجم الهرم؟', '[{"id":"a","text":"60 cm³"},{"id":"b","text":"40 cm³"},{"id":"c","text":"30 cm³"},{"id":"d","text":"20 cm³"}]'::jsonb, 'd', 'مساحة القاعدة المثلّثية: $S = \frac{1}{2} \times 3 \times 4 = 6 \text{ cm}^2$. إذن $V = \frac{1}{3} \times 6 \times 10 = \frac{60}{3} = 20 \text{ cm}^3$.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d3df261-f148-5b0b-84a6-74ef0aa0e9c4', '00789172-89dd-5cc2-8af9-730645c3c113', 'كرة نصف قطرها 3 cm وأسطوانة نصف قطرها 3 cm وارتفاعها 4 cm. أيّهما حجمه أكبر؟', '[{"id":"a","text":"الكرة أكبر"},{"id":"b","text":"الأسطوانة أكبر"},{"id":"c","text":"حجماهما متساويان"},{"id":"d","text":"لا يمكن المقارنة"}]'::jsonb, 'c', 'حجم الكرة: $V_K = \frac{4}{3}\pi \times 3^3 = \frac{4}{3} \times 27\pi = 36\pi \text{ cm}^3$. حجم الأسطوانة: $V_A = \pi \times 3^2 \times 4 = 36\pi \text{ cm}^3$. الحجمان متساويان! هذه نتيجة مدهشة تستحقّ الحفظ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03d725a0-aedc-5bd2-a40d-fa740eee3cba', '00789172-89dd-5cc2-8af9-730645c3c113', 'هرم قاعدته مربّع ضلعه 4 cm وارتفاعه 3 cm. إذا ضاعف الارتفاع فقط ليصبح 6 cm، فبكم يتضاعف الحجم؟', '[{"id":"a","text":"يتضاعف مرّتين (×2)"},{"id":"b","text":"يتضاعف ثلاث مرّات (×3)"},{"id":"c","text":"يتضاعف أربع مرّات (×4)"},{"id":"d","text":"يبقى كما هو"}]'::jsonb, 'a', '$V_1 = \frac{1}{3} \times 16 \times 3 = 16 \text{ cm}^3$. $V_2 = \frac{1}{3} \times 16 \times 6 = 32 \text{ cm}^3$. النسبة $V_2 / V_1 = 32/16 = 2$. الحجم يتضاعف مرّتين لأنّ صيغة الحجم خطّية في h.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce97f02a-d74c-52b0-b0e1-7239b8e55545', '00789172-89dd-5cc2-8af9-730645c3c113', 'مخروط نصف قطر قاعدته 6 cm وارتفاعه 8 cm. ما المساحة الجانبية له؟ (π ≈ 3.14)', '[{"id":"a","text":"150.72 cm²"},{"id":"b","text":"301.44 cm²"},{"id":"c","text":"188.4 cm²"},{"id":"d","text":"376.8 cm²"}]'::jsonb, 'c', 'الطول المائل: $l = \sqrt{r^2+h^2} = \sqrt{6^2+8^2} = \sqrt{36+64} = \sqrt{100} = 10 \text{ cm}$. المساحة الجانبية: $S = \pi r l = 3.14 \times 6 \times 10 = 188.4 \text{ cm}^2$.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

